    /// <summary>
///    Retrieves a <c>WMSLocationId</c>, associated with the production order of this job.
/// </summary>
/// <returns>
///    The <c>WMSLocationId</c> associated with the job.
/// </returns>
internal WMSLocationId getWMSLocationId()
{
    WMSLocationId wMSLocationId;
    ProdTable prodTable = ProdTable::find(this.JobRef());

    if (prodTable)
    {
        wMSLocationId = InventDim::find(prodTable.InventDimId).wMSLocationId;
    }

    return wMSLocationId;
}
